"use strict";(self.webpackChunktorabian_github_io=self.webpackChunktorabian_github_io||[]).push([[9368],{4923:(e,n,a)=>{a.r(n),a.d(n,{assets:()=>l,contentTitle:()=>r,default:()=>h,frontMatter:()=>i,metadata:()=>t,toc:()=>d});const t=JSON.parse('{"type":"mdx","permalink":"/insight/how-to-build-a-scalable-backend-that-costs-almost-nothing-to-run","source":"@site/src/pages/insight/how-to-build-a-scalable-backend-that-costs-almost-nothing-to-run.md","title":"How to Build a Scalable Backend That Costs Almost Nothing to Run","description":"Almost every software, mobile application, or website needs a \\"backend.\\" This part of a software product","frontMatter":{},"unlisted":false}');var s=a(4848),o=a(8453);const i={},r="How to Build a Scalable Backend That Costs Almost Nothing to Run",l={},d=[{value:"Why a Good Backend Matters and Changes the Future of a Digital Product",id:"why-a-good-backend-matters-and-changes-the-future-of-a-digital-product",level:2},{value:"Top Strategies to Expect in Your Backend Systems",id:"top-strategies-to-expect-in-your-backend-systems",level:2},{value:"Technology Doesn&#39;t Matter? That&#39;s Wrong",id:"technology-doesnt-matter-thats-wrong",level:2},{value:"Avoid Excessive Use of External Libraries",id:"avoid-excessive-use-of-external-libraries",level:2},{value:"Avoid Shiny Tools That Emerge Every Weekend",id:"avoid-shiny-tools-that-emerge-every-weekend",level:2},{value:"Stick to Established Databases",id:"stick-to-established-databases",level:2},{value:"Export a Clear API Spec or SDKs",id:"export-a-clear-api-spec-or-sdks",level:2},{value:"Avoid Premature Scaling",id:"avoid-premature-scaling",level:2},{value:"Conclusion",id:"conclusion",level:2}];function c(e){const n={h1:"h1",h2:"h2",header:"header",li:"li",p:"p",ul:"ul",...(0,o.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsx)(n.h1,{id:"how-to-build-a-scalable-backend-that-costs-almost-nothing-to-run",children:"How to Build a Scalable Backend That Costs Almost Nothing to Run"})}),"\n",(0,s.jsx)(n.p,{children:'Almost every software, mobile application, or website needs a "backend." This part of a software product\nusually handles the database, manages users, and processes transactions. It also provides APIs for mobile apps and web applications.'}),"\n",(0,s.jsx)(n.p,{children:"After 20 years of experience in the business, I have seen most of the paths small startups and large enterprises take, and what is helpful to consider from the beginning of a project."}),"\n",(0,s.jsx)(n.h2,{id:"why-a-good-backend-matters-and-changes-the-future-of-a-digital-product",children:"Why a Good Backend Matters and Changes the Future of a Digital Product"}),"\n",(0,s.jsx)(n.p,{children:"Let's assume you've built the product and customers are using it. Over a short period,\nit becomes hard to add features, debugging takes longer, and release cycles slow down.\nThe goal of the software or app was to solve a business problem, but now maintaining\nthe software itself becomes the main task."}),"\n",(0,s.jsx)(n.p,{children:"Some product managers try to solve this issue by adding more people to the team, without\naddressing the real problem: a simple, reliable backend is often the bottleneck\nof any web or mobile app. The fact is, there isn't a linear relation between resources needed\nto run software and the number of users. Large apps, such as WhatsApp, have been running with the same amount of\nhuman resources from 100K users to millions over a long period."}),"\n",(0,s.jsx)(n.h2,{id:"top-strategies-to-expect-in-your-backend-systems",children:"Top Strategies to Expect in Your Backend Systems"}),"\n",(0,s.jsx)(n.p,{children:"Although building anything in life is challenging, the backend of a project\ndoesn't have to be unnecessarily hard. Regardless of who is building it, keep the following\nheadlines in mind when creating your backend system."}),"\n",(0,s.jsx)(n.h2,{id:"technology-doesnt-matter-thats-wrong",children:"Technology Doesn't Matter? That's Wrong"}),"\n",(0,s.jsx)(n.p,{children:"You may have heard things like:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"\u201cIt would work with any programming language.\u201d"}),"\n",(0,s.jsx)(n.li,{children:"\u201cIt doesn\u2019t matter which server it runs on.\u201d"}),"\n",(0,s.jsx)(n.li,{children:"\u201cAll databases are basically the same.\u201d"}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"The reality is, subtle differences in any aspect of a project \u2014 not just software \u2014 can have a huge impact\nafter the initial stages."}),"\n",(0,s.jsx)(n.p,{children:"For example, if you are using a programming language such as Golang, your binaries are small even for large\nprojects, they are standalone installable, and often do not need advanced configuration to keep them running.\nThey can also be configured to run automatically and installed by a sysadmin without access to the development team.\nCompare this to a scripting language such as Ruby, PHP, or Node.js, which require constant maintenance\njust to keep running. Of course, similar results can be achieved if someone really wants to, but that is not the usual practice."}),"\n",(0,s.jsx)(n.p,{children:"For a large enterprise owning 25% of the energy market in Europe, paying\n\u20ac90,000 monthly for a database and 20 people to maintain MongoDB may not matter. But for a small product,\nwith a limited profit margin, even small cost differences matter. Reducing operational costs from $10,000 to $500\nis $9,500 saved \u2014 significant for a small team deciding the fate of their survival."}),"\n",(0,s.jsx)(n.p,{children:"Therefore, it is critical to choose the right tools for the job from the beginning. In most cases, you want\na relational database with compiled, extremely fast binaries to execute your business logic,\nsuch as SQL databases and the Golang programming language."}),"\n",(0,s.jsx)(n.h2,{id:"avoid-excessive-use-of-external-libraries",children:"Avoid Excessive Use of External Libraries"}),"\n",(0,s.jsx)(n.p,{children:"Many projects I\u2019ve seen over the past 10 years rely heavily on external tools: Keycloak, Firebase,\nbuild tools like Fastlane, and hundreds more. I remember when I was starting out,\nnone of these existed, yet we managed to build all features with just 4\u20135 people."}),"\n",(0,s.jsx)(n.p,{children:"Outsourcing major parts of the application and depending on external tools does not save time;\nit adds cost and forces you to adapt your workflow."}),"\n",(0,s.jsx)(n.p,{children:"Examples:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"You don\u2019t need external identity management. Build it inside your product. Security can be handled properly,\nand by not using common solutions in obvious ways, you can gain security through obscurity."}),"\n",(0,s.jsx)(n.li,{children:"Most apps do not need advanced CI/CD automation. If your app is released monthly, just build it locally and deploy.\nThis saves hours of maintenance."}),"\n",(0,s.jsx)(n.li,{children:"Many projects can be maintained with 10\u201315 GB of SQL tables. Large 1TB databases are often unnecessary; careful design with standard tables is usually sufficient."}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:'Fear drives developers and project managers to avoid new approaches. If a major product solves an issue, take a look at how it works. Don\u2019t be intimidated by terms like "load balancer websocket handling"; in the end, it\u2019s just multiple instances of the same app and a pool of socket connections.'}),"\n",(0,s.jsx)(n.h2,{id:"avoid-shiny-tools-that-emerge-every-weekend",children:"Avoid Shiny Tools That Emerge Every Weekend"}),"\n",(0,s.jsx)(n.p,{children:"For most products, new tools are distractions: new deployment interfaces, databases, CI/CD tools.\nMany critical programs that generate billions of dollars are written in C, C++, and PHP \u2014 proving that core tools rarely change."}),"\n",(0,s.jsx)(n.p,{children:"For small teams with tight budgets, constantly chasing new front-end frameworks or libraries is unnecessary.\nThe focus should always be on solving real-world problems, not rewriting code constantly."}),"\n",(0,s.jsx)(n.h2,{id:"stick-to-established-databases",children:"Stick to Established Databases"}),"\n",(0,s.jsx)(n.p,{children:"The database stores information \u2014 mostly the backend\u2019s job. Relational databases have been the standard for decades.\nOracle, MySQL, SQLite, and SQL Server have been dominant for a long time."}),"\n",(0,s.jsx)(n.p,{children:"The explosion of new databases can overwhelm teams. In most cases, sticking to a major database is enough.\nAdding new brands for such a critical part of the app complicates long-term maintenance."}),"\n",(0,s.jsx)(n.p,{children:"Although ORMs (like Entity Framework) accelerate work initially, serious applications often require writing plain SQL later.\nFor new projects, I advise avoiding ORMs altogether and writing simple SQL directly, which makes maintenance minimal and extends the software\u2019s life for decades."}),"\n",(0,s.jsx)(n.p,{children:"In the Node.js ecosystem, tools like TypeORM, Sequelize, and Sails ORM are distractions.\nWriting SQL scripts manually and managing them carefully is more reliable, especially for critical systems like banks."}),"\n",(0,s.jsx)(n.p,{children:"Non-relational databases like MongoDB may seem convenient at first, but they introduce long-term risks if the data is important or critical."}),"\n",(0,s.jsx)(n.h2,{id:"export-a-clear-api-spec-or-sdks",children:"Export a Clear API Spec or SDKs"}),"\n",(0,s.jsx)(n.p,{children:"A major cost in development comes from not knowing what exists in the system.\nMost projects plan only 2 weeks ahead, features get forgotten, and developers leave,\nleaving no clear understanding of the backend\u2019s capabilities."}),"\n",(0,s.jsx)(n.p,{children:"API specs, via Swagger/OpenAPI, are essential, but only document request and response data.\nDocumenting logic, error codes, and workflows adds enormous value."}),"\n",(0,s.jsx)(n.p,{children:"Even if you are the sole developer, proper documentation ensures that future you can understand the system in 2 years."}),"\n",(0,s.jsx)(n.h2,{id:"avoid-premature-scaling",children:"Avoid Premature Scaling"}),"\n",(0,s.jsx)(n.p,{children:"There is a tendency to overinvest in scaling. Reality: 90% of products fail.\nOverbuilding infrastructure for a product unlikely to succeed is wasted effort and resources."}),"\n",(0,s.jsx)(n.p,{children:"Focus on making the backend reliable, avoiding flashy features like premature scaling.\nFor most products, even useful apps will never reach thousands of users quickly."}),"\n",(0,s.jsx)(n.h2,{id:"conclusion",children:"Conclusion"}),"\n",(0,s.jsx)(n.p,{children:"To say how to build a zero maintance backend is hard, but as summary:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"Use reliable languages, such as Go, and Java"}),"\n",(0,s.jsx)(n.li,{children:"Write most things in house"}),"\n",(0,s.jsx)(n.li,{children:"Avoid techy flashy stuff which doesn't serve"}),"\n",(0,s.jsx)(n.li,{children:"Document, code and API"}),"\n",(0,s.jsx)(n.li,{children:"Make it self installable"}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"Hope this content did help a bit, so you can have best out of your budget."})]})}function h(e={}){const{wrapper:n}={...(0,o.R)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(c,{...e})}):c(e)}},8453:(e,n,a)=>{a.d(n,{R:()=>i,x:()=>r});var t=a(6540);const s={},o=t.createContext(s);function i(e){const n=t.useContext(o);return t.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:i(e.components),t.createElement(o.Provider,{value:n},e.children)}}}]);